Here's how to test `DataFetcher` with MSTest, covering success, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static HttpClient CreateMockClient(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        return new HttpClient(new FakeHandler(handler));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var client = CreateMockClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello world")
            }));
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var client = CreateMockClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.InternalServerError)));
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        var client = CreateMockClient(async (_, ct) =>
        {
            await Task.Delay(Timeout.Infinite, ct); // Simulate slow server
            return new HttpResponseMessage(); // Never reached
        });
        var fetcher = new DataFetcher(client);

        // Act & Assert
        cts.Cancel();
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TokenFromTestContext_CooperatesWithTimeout()
    {
        // Arrange — handler respects cancellation
        var client = CreateMockClient(async (_, ct) =>
        {
            await Task.Delay(100, ct);
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("fast response")
            };
        });
        var fetcher = new DataFetcher(client);

        // Act — uses TestContext.CancellationToken so [Timeout] can abort
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("fast response", result);
    }

    // Minimal fake handler for HttpClient
    private sealed class FakeHandler(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> onSend)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => onSend(request, cancellationToken);
    }
}
```

**Key takeaways:**

| Pattern | Why |
|---------|-----|
| `[Timeout(N)]` + `_testContext.CancellationToken` | MSTest fires the token when timeout elapses — cooperative cancellation |
| `Assert.ThrowsExactlyAsync<T>` | Verifies the exact exception type from async code |
| `FakeHandler` | Avoids real HTTP; lets you simulate delays, errors, and cancellation |
| Separate `CancellationTokenSource` | Tests explicit caller-initiated cancellation independently of test timeout |

Pass `TestContext.CancellationToken` into all production async calls so that the `[Timeout]` attribute can actually abort a hung test instead of waiting forever.
